import Vue from 'vue'
import 'fullpage.js/vendors/scrolloverflow' // Optional. When using scrollOverflow:true
import VueFullPage from 'vue-fullpage.js' // Import vue-fullpage
import './assets/handler.js' // Import Clickhandler
import './../node_modules/@fortawesome/fontawesome-free/css/all.css'; // Import fontawesome Icons

import App from './App.vue' // Import first Component


Vue.config.productionTip = false

Vue.use(VueFullPage); // Tell vue to use vue-fullpage

new Vue({
	render: h => h(App), // render function
}).$mount('#app') // mount to element div#app